const yesterdayData = $items('Postgres Yesterday');
const monthData = $items('Postgres Month');

const formatter = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' });

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const formattedDate = yesterday.toLocaleDateString('pt-BR');

let msg = `*📊 BRIEFING DIÁRIO - ${formattedDate}*\n_Dados consolidados das operações_\n\n`;

const lojas = ['Sobral', 'Itapipoca'];

for (const l of lojas) {
    // Filter rows by store
    const yRows = yesterdayData.filter(i => i.json.loja && i.json.loja.toLowerCase() === l.toLowerCase()).map(i => i.json);
    const mRows = monthData.filter(i => i.json.loja && i.json.loja.toLowerCase() === l.toLowerCase()).map(i => i.json);

    msg += `🏢 *LOJA ${l.toUpperCase()}*\n`;

    // YESTERDAY AGGREGATION
    if (yRows.length > 0) {
        let totalY = 0, volY = 0;
        let metaTop1Y = 0;
        for (const row of yRows) {
            totalY += parseFloat(row.valor_total_vendido) || 0;
            volY += parseInt(row.quantidade_vendas) || 0;
            metaTop1Y += parseFloat(row.meta_top1_diaria) || 0;
        }

        const tmY = volY > 0 ? totalY / volY : 0;

        msg += `*Ontem (Total):*\n`;
        msg += `- Faturou: *${formatter.format(totalY)}* (${volY} vendas) | Ticket Médio: *${formatter.format(tmY)}*\n`;

        if (totalY >= metaTop1Y && metaTop1Y > 0) {
            msg += `- Meta Top 1: *Batida!* 🎉 (Superou em ${formatter.format(totalY - metaTop1Y)})\n`;
        } else if (metaTop1Y > 0) {
            msg += `- Meta Top 1: Não atingida. Faltou *${formatter.format(metaTop1Y - totalY)}*.\n`;
        }

        // Seller breakdown yesterday
        msg += `_Vendedores (Ontem):_\n`;
        for (const row of yRows) {
            const vTotal = parseFloat(row.valor_total_vendido) || 0;
            if (vTotal > 0) {
                msg += `  👤 ${row.nome_vendedor}: ${formatter.format(vTotal)}\n`;
            }
        }
    } else {
        msg += `*Ontem:* Sem vendas registradas.\n`;
    }

    // MONTH AGGREGATION
    if (mRows.length > 0) {
        let totalM = 0, volM = 0;
        let metaMinM = 0, metaTop1M = 0, metaTop2M = 0, metaMasterM = 0;

        for (const row of mRows) {
            totalM += parseFloat(row.valor_total_vendido) || 0;
            volM += parseInt(row.quantidade_vendas) || 0;
            metaMinM += parseFloat(row.meta_minima) || 0;
            metaTop1M += parseFloat(row.meta_top1) || 0;
            metaTop2M += parseFloat(row.meta_top2) || 0;
            metaMasterM += parseFloat(row.meta_master) || 0;
        }

        const tmM = volM > 0 ? totalM / volM : 0;

        msg += `\n*Mês Atual (Consolidado):*\n`;
        msg += `- Faturou: *${formatter.format(totalM)}* (${volM} vendas) | Ticket Médio: *${formatter.format(tmM)}*\n`;

        msg += `_Distância para as Metas (Mês):_\n`;

        const checkMeta = (nome, metaVal, total) => {
            if (metaVal <= 0) return '';
            if (total >= metaVal) {
                return `  🎯 ${nome}: *Batida!* (Superou em ${formatter.format(total - metaVal)})\n`;
            } else {
                return `  📉 ${nome}: Faltam *${formatter.format(metaVal - total)}*\n`;
            }
        };

        msg += checkMeta('Mínima', metaMinM, totalM);
        msg += checkMeta('Top 1', metaTop1M, totalM);
        msg += checkMeta('Top 2', metaTop2M, totalM);
        msg += checkMeta('Master', metaMasterM, totalM);

        // Seller breakdown month
        msg += `_Vendedores (Mês):_\n`;
        for (const row of mRows) {
            const vTotal = parseFloat(row.valor_total_vendido) || 0;
            if (vTotal > 0) {
                msg += `  👤 ${row.nome_vendedor}: ${formatter.format(vTotal)}\n`;
            }
        }
    } else {
        msg += `\n*Mês Atual:* Sem vendas registradas.\n`;
    }

    msg += `\n`;
}

return [{ json: { message: msg.trim() } }];
